import{b as e,J as a,g as l,j as r}from"./chunks/framework.DVAsBjJ_.js";const x=JSON.parse('{"title":"납부 현황 집계","description":"","frontmatter":{},"headers":[],"relativePath":"payment/status.md","filePath":"payment/status.md","lastUpdated":1780509109000}'),d={name:"payment/status.md"};function n(i,t,s,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="납부-현황-집계" tabindex="-1">납부 현황 집계 <a class="header-anchor" href="#납부-현황-집계" aria-label="Permalink to &quot;납부 현황 집계&quot;">​</a></h1><p>프로젝트의 전체 수납 데이터를 차수별, 타입별, 회차별로 집계하여 통계 정보를 제공하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>계약 납부 관리 &gt; 납부 현황 집계</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>특정 <strong>기준일자</strong>를 설정하여 해당 시점까지의 누적 수납 실적을 다각도로 분석합니다. 매출 목표 대비 실제 계약 및 수납 성과를 확인하는 [수납요약]과 프로젝트 전체의 자금 흐름과 미수금 현황을 회차별로 집계하는 [총괄집계] 두 가지 리포트를 제공합니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li>기준일자 설정을 통한 특정 시점의 실적 조회</li><li>차수 및 타입별 계약/수납 현황 집계 (수납요약)</li><li>회차별 매출, 수납, 미수금 및 기간별 미수 현황 집계 (총괄집계)</li><li>각 집계 화면별 엑셀 다운로드 지원</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-기준일자-설정" tabindex="-1">1. 기준일자 설정 <a class="header-anchor" href="#_1-기준일자-설정" aria-label="Permalink to &quot;1. 기준일자 설정&quot;">​</a></h3><p>통계 산출의 기준이 되는 날짜를 지정합니다. 과거 일자를 선택하여 해당 시점의 보고서를 재현할 수 있습니다.</p><h3 id="_2-수납요약-탭" tabindex="-1">2. 수납요약 (탭) <a class="header-anchor" href="#_2-수납요약-탭" aria-label="Permalink to &quot;2. 수납요약 (탭)&quot;">​</a></h3><p>프로젝트의 물량(세대수)과 금액을 기준으로 계약 및 수납 성과를 입체적으로 보여줍니다.</p><h4 id="주요-표시-항목" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">항목</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;">차수 / 타입</td><td style="text-align:left;">설정된 프로젝트의 계약 그룹 및 평형 정보</td></tr><tr><td style="text-align:left;">전체 매출액</td><td style="text-align:left;">[수입 예산 등록]에 설정된 해당 타입의 총 목표 금액</td></tr><tr><td style="text-align:left;">계약 세대(실)수</td><td style="text-align:left;">현재까지 체결된 계약 건수</td></tr><tr><td style="text-align:left;">계약 금액</td><td style="text-align:left;">체결된 계약의 총 공급가액 합계</td></tr><tr><td style="text-align:left;">실수납 금액</td><td style="text-align:left;">실제로 입금 처리된 순수 납부액 합계</td></tr><tr><td style="text-align:left;">미수 금액</td><td style="text-align:left;">계약 금액 중 아직 수납되지 않은 잔액</td></tr><tr><td style="text-align:left;">미계약 세대/금액</td><td style="text-align:left;">전체 매출 목표 중 아직 계약되지 않은 잔여 물량 및 금액</td></tr></tbody></table><h3 id="_3-총괄집계-탭" tabindex="-1">3. 총괄집계 (탭) <a class="header-anchor" href="#_3-총괄집계-탭" aria-label="Permalink to &quot;3. 총괄집계 (탭)&quot;">​</a></h3><p>회차별(계약금, 중도금, 잔금 등) 약정 기준에 따라 자금의 회수 현황과 미수금의 성격을 분석합니다.</p><h4 id="주요-표시-항목-1" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목-1" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">구분</th><th style="text-align:left;">주요 내용</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>기본 정보</strong></td><td style="text-align:left;">각 회차별 공식 약정일(기준일)</td></tr><tr><td style="text-align:left;"><strong>계약 현황</strong></td><td style="text-align:left;">계약분, 미계약분, 총계 및 현재 계약율</td></tr><tr><td style="text-align:left;"><strong>수납 현황</strong></td><td style="text-align:left;">수납액, 할인료, 연체료, 실수납액 및 수납율</td></tr><tr><td style="text-align:left;"><strong>기간도래 미수</strong></td><td style="text-align:left;">약정일이 지났음에도 수납되지 않은 미수금, 연체료 및 소계</td></tr><tr><td style="text-align:left;"><strong>기간미도래 미수</strong></td><td style="text-align:left;">아직 약정일이 되지 않아 수납 대기 중인 금액</td></tr><tr><td style="text-align:left;"><strong>총계</strong></td><td style="text-align:left;">전체 미수금 합계 및 전체 분양가 대비 미수율</td></tr></tbody></table><h2 id="💡-활용-가이드" tabindex="-1">💡 활용 가이드 <a class="header-anchor" href="#💡-활용-가이드" aria-label="Permalink to &quot;💡 활용 가이드&quot;">​</a></h2><ul><li><strong>수납요약 리포트</strong>: 분양 초기나 평형별 분양 성과를 집중적으로 관리해야 할 때 유용합니다. [수입 예산 등록] 데이터가 선행되어야 정확한 통계가 산출됩니다.</li><li><strong>총괄집계 리포트</strong>: 공사 중 중도금 회수 현황이나 자금 계획을 수립할 때 유용합니다. 특히 &#39;기간도래 미수&#39;와 &#39;연체료&#39; 현황을 통해 채권 관리의 우선순위를 정할 수 있습니다.</li></ul>',20)])])}const y=e(d,[["render",n]]);export{x as __pageData,y as default};
